#include<bits/stdc++.h>
using namespace std;

int main() {
	int n, a[210][210], b[210], ant, cnt;
	bool c = 0;
	cin >> n;
	ant = n * n;
	cnt = n;
	for (int i = 0; ant != 0; i++) {
		cin >> b[i];
		for (; b[i] != 0; b[i]--) {
			ant--;
			cout << c;
			cnt--;
			if (cnt == 0) {
				cout << endl;
				cnt = n;
			}
		}
		c = !c;
	}
	return 0;
}
